#include <vector>
#include <cmath>

long long solve(std::vector<long long> nums) {
    // Function to check if a number is prime
    bool isPrime(int n) {
        if (n <= 1) return false;
        if (n == 2) return true;
        if (n % 2 == 0) return false;
        for (int i = 3; i <= sqrt(n); i += 2) {
            if (n % i == 0) return false;
        }
        return true;
    }

    long long sumA = 0;
    long long sumB = 0;

    for (int i = 0; i < nums.size(); ++i) {
        if (isPrime(i)) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }

    return std::abs(sumA - sumB);
}
